import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, onValue } from "firebase/database";

function App() {
  const [leftFoot, setLeftFoot] = useState(null);
  const [rightFoot, setRightFoot] = useState(null);

  useEffect(() => {
    const leftRef = ref(database, "leftFoot");
    const rightRef = ref(database, "rightFoot");

    const unsubscribeLeft = onValue(leftRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1];
        setLeftFoot(latest);
      } else {
        setLeftFoot(null);
      }
    });

    const unsubscribeRight = onValue(rightRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        const latest = entries[entries.length - 1];
        setRightFoot(latest);
      } else {
        setRightFoot(null);
      }
    });

    return () => {
      unsubscribeLeft();
      unsubscribeRight();
    };
  }, []);

  const renderFootData = (footData, label) => {
    if (!footData)
      return (
        <div className="p-6 border rounded-xl shadow bg-white w-full max-w-md text-center">
          <h2 className="text-xl font-semibold text-gray-700">{label}</h2>
          <p className="text-gray-500">No data available</p>
        </div>
      );

    return (
      <div className="p-6 border rounded-xl shadow bg-white w-full max-w-md">
        <h2 className="text-2xl font-bold text-blue-600 mb-2">{label}</h2>
        <p className="text-sm text-gray-600 mb-1">
          <span className="font-semibold">Timestamp:</span> {footData.timestamp}
        </p>
        <p className="text-sm text-gray-600 mb-3">
          <span className="font-semibold">Force:</span> {footData.force} N
        </p>

        <div className="mb-3">
          <h4 className="text-md font-semibold text-gray-800">Accelerometer</h4>
          <ul className="list-disc ml-6 text-sm text-gray-700">
            <li>X: {footData.accel?.x}</li>
            <li>Y: {footData.accel?.y}</li>
            <li>Z: {footData.accel?.z}</li>
          </ul>
        </div>

        <div>
          <h4 className="text-md font-semibold text-gray-800">Gyroscope</h4>
          <ul className="list-disc ml-6 text-sm text-gray-700">
            <li>X: {footData.gyro?.x}</li>
            <li>Y: {footData.gyro?.y}</li>
            <li>Z: {footData.gyro?.z}</li>
          </ul>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gray-100 p-6 flex flex-col items-center space-y-8">
      <h1 className="text-3xl font-bold text-gray-800">Latest Foot Sensor Data</h1>
      <div className="flex flex-col md:flex-row gap-6">
        {renderFootData(leftFoot, "Left Foot")}
        {renderFootData(rightFoot, "Right Foot")}
      </div>
    </div>
  );
}

export default App;
